#include <iostream>

class Box {
public:
    int side;
    int volume() const { return side * side * side; }
};

void printVolume(const Box& b) {
    std::cout << b.volume() << "\n";
}

int main() {
    Box b;
    b.side = 3;
    printVolume(b);
    b.side = 4;
    printVolume(b);
}
